const MISSING_CATALOG_MESSAGE = 'No se encontr� concepts.normalized.json en la ruta indicada. Revisa catalogPath y confirma que existe el archivo. Inicia n8n con NODE_FUNCTION_ALLOW_BUILTIN=fs,path.';

