function ensureAbsoluteCatalogPath(rawPath, label = "catalogPath") {
  const normalized = typeof rawPath === 'string' ? rawPath.trim() : '';
  if (!normalized) {
    throw new Error(label + ' es requerido y debe ser absoluto en n8n 2.4.4. Usa: ' + DEFAULT_CATALOG_PATH);
  }
  if (!path.isAbsolute(normalized)) {
    throw new Error(catalogHintMessage);
  }
  return path.normalize(normalized);
}

function resolveCatalogPath(rawPath) {
  const catalogPath = ensureAbsoluteCatalogPath(rawPath);
  if (!fs.existsSync(catalogPath)) {
    throw new Error(MISSING_CATALOG_MESSAGE + ' Ruta usada: ' + catalogPath);
  }
  return catalogPath;
}

function runManualScoring(message, options = {}) {
  const normalizedMessage = (message || '').toString().trim();
  if (!normalizedMessage) {
    throw new Error('runManualScoring: message is required.');
  }
  const catalogPath = resolveCatalogPath(options.catalogPath || DEFAULT_CATALOG_PATH);
  const catalog = JSON.parse(fs.readFileSync(catalogPath, 'utf8'));
  const raw = classifyMessage(normalizedMessage, catalog);
  return buildN8nResponse(raw, normalizedMessage);
}


